static PyObject *
Segment_add(SegmentObject *self, PyObject *args)
{
    Py_ssize_t n = PyTuple_GET_SIZE(args);
    PyObject *list = PyList_New(n + 1);
    if (!list)
        return NULL;
    Py_INCREF(self);
    PyList_SET_ITEM(list, 0, (PyObject *)self);
    for (Py_ssize_t i = 0; i < n; i++) {
        PyObject *it = PyTuple_GET_ITEM(args, i);
        Py_INCREF(it);
        PyList_SET_ITEM(list, i + 1, it);
    }
    PyObject *tl =
        PyObject_CallFunctionObjArgs((PyObject *)&TimelineType, list, NULL);
    Py_DECREF(list);
    return tl;
}


