    PyObject *pathobj;
    if (!PyArg_ParseTuple(args, "O&", PyUnicode_FSConverter, &pathobj))
        return NULL;
    wfm_compose_state_t *st = wfm_compose_from_file(PyBytes_AS_STRING(pathobj));
